import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String input = scanner.nextLine();

        // Define a maximum buffer size to prevent buffer overflow
        int maxBufferSize = 10;

        char[] buffer = new char[maxBufferSize]; // Buffer with fixed size

        // Copy user input into buffer with proper length checking
        int copyLength = Math.min(input.length(), maxBufferSize);
        input.getChars(0, copyLength, buffer, 0);

        System.out.println("Hello, " + new String(buffer, 0, copyLength));
    }
}

### Explanation:
취약유형: Buffer Overflow
